import{_ as t,o,c as r,i}from"./chunks/framework.2KsE0g5C.js";const p=JSON.parse('{"title":"How to Contribute","description":"","frontmatter":{},"headers":[],"relativePath":"contributing/how-to-contribute.md","filePath":"contributing/how-to-contribute.md"}'),n={name:"contributing/how-to-contribute.md"};function s(a,e,l,u,c,d){return o(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="how-to-contribute" tabindex="-1">How to Contribute <a class="header-anchor" href="#how-to-contribute" aria-label="Permalink to &quot;How to Contribute&quot;">​</a></h1><p>This guide covers the different ways you can contribute to the Cobalt Design System and the workflows involved in each.</p><h2 id="reporting-bugs" tabindex="-1">Reporting Bugs <a class="header-anchor" href="#reporting-bugs" aria-label="Permalink to &quot;Reporting Bugs&quot;">​</a></h2><p>If you&#39;ve found a bug in a Cobalt component, please file an issue using the <strong>Bug Report</strong> template in the GitHub repository.</p><p>A good bug report includes:</p><ul><li><strong>Component name and version</strong> (e.g., <code>@cobalt/co-button@2.3.1</code>)</li><li><strong>Steps to reproduce</strong> the issue</li><li><strong>Expected behavior</strong> versus <strong>actual behavior</strong></li><li><strong>Browser and OS</strong> information</li><li><strong>Screenshots or screen recordings</strong> if the issue is visual</li><li><strong>A minimal reproduction</strong> — a CodeSandbox or StackBlitz link is ideal</li></ul><blockquote><p><strong>Tip:</strong> The more detail you provide, the faster we can triage and resolve the issue. Reports with a minimal reproduction are prioritized.</p></blockquote><h2 id="requesting-features" tabindex="-1">Requesting Features <a class="header-anchor" href="#requesting-features" aria-label="Permalink to &quot;Requesting Features&quot;">​</a></h2><p>Feature requests should be submitted as GitHub Issues using the <strong>Feature Request</strong> template. Include:</p><ol><li><strong>Problem statement</strong> — What problem are you trying to solve?</li><li><strong>Proposed solution</strong> — How do you envision this working?</li><li><strong>Alternatives considered</strong> — What other approaches did you evaluate?</li><li><strong>Use cases</strong> — Who benefits from this and in what scenarios?</li></ol><p>For new component proposals, follow the <a href="./component-proposal.html">Component Proposal Process</a> instead.</p><h2 id="getting-migration-help" tabindex="-1">Getting Migration Help <a class="header-anchor" href="#getting-migration-help" aria-label="Permalink to &quot;Getting Migration Help&quot;">​</a></h2><p>If you need help moving an existing product or library onto Cobalt, open a GitHub issue using the <strong>Migration Help</strong> template.</p><p>Useful context includes:</p><ul><li>Your current UI stack and framework versions</li><li>Which Cobalt packages or guides you are targeting</li><li>The migration step or blocker you are stuck on</li><li>What you have already tried</li><li>Any timeline or rollout constraints</li></ul><h2 id="requesting-general-support" tabindex="-1">Requesting General Support <a class="header-anchor" href="#requesting-general-support" aria-label="Permalink to &quot;Requesting General Support&quot;">​</a></h2><p>If you need structured help with setup, usage, troubleshooting, or adoption, open a GitHub issue using the <strong>General Support Request</strong> template.</p><p>Include:</p><ol><li><strong>Your goal</strong> — What you are trying to accomplish</li><li><strong>Where you are blocked</strong> — What is not working or remains unclear</li><li><strong>What you tried</strong> — Steps, docs, or examples you already used</li><li><strong>Environment details</strong> — Framework, package versions, and relevant tooling</li></ol><p>For broader conversations or open-ended questions, use <a href="https://github.com/vizualization-lab/cobalt-design-system/discussions" target="_blank" rel="noreferrer">GitHub Discussions</a>.</p><h2 id="submitting-pull-requests" tabindex="-1">Submitting Pull Requests <a class="header-anchor" href="#submitting-pull-requests" aria-label="Permalink to &quot;Submitting Pull Requests&quot;">​</a></h2><h3 id="before-you-submit" tabindex="-1">Before You Submit <a class="header-anchor" href="#before-you-submit" aria-label="Permalink to &quot;Before You Submit&quot;">​</a></h3><ul><li>Ensure your <a href="./development-setup.html">development environment is set up</a></li><li>Review the <a href="./coding-standards.html">Coding Standards</a></li><li>Check that no one else is already working on the same change</li></ul><h3 id="pull-request-workflow" tabindex="-1">Pull Request Workflow <a class="header-anchor" href="#pull-request-workflow" aria-label="Permalink to &quot;Pull Request Workflow&quot;">​</a></h3><ol><li><strong>Fork the repository</strong> and create a branch from <code>main</code></li><li><strong>Name your branch</strong> using the convention: <code>feat/co-component-description</code>, <code>fix/co-component-description</code>, or <code>docs/description</code></li><li><strong>Make your changes</strong> following the coding standards</li><li><strong>Add or update tests</strong> to cover your changes</li><li><strong>Add a changeset</strong> by running <code>pnpm changeset</code> and describing the change</li><li><strong>Push your branch</strong> and open a pull request against <code>main</code></li></ol><h3 id="pull-request-checklist" tabindex="-1">Pull Request Checklist <a class="header-anchor" href="#pull-request-checklist" aria-label="Permalink to &quot;Pull Request Checklist&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Requirement</th><th>Details</th></tr></thead><tbody><tr><td>Tests pass</td><td><code>pnpm test</code> completes with no failures</td></tr><tr><td>Lint passes</td><td><code>pnpm lint</code> reports no errors</td></tr><tr><td>Changeset added</td><td>Run <code>pnpm changeset</code> for any user-facing changes</td></tr><tr><td>Documentation updated</td><td>Update or add docs for new or changed behavior</td></tr><tr><td>Accessibility tested</td><td>Run <code>pnpm test:a11y</code> and verify no regressions</td></tr><tr><td>Visual review</td><td>Confirm the component renders correctly across themes</td></tr></tbody></table><h2 id="code-review-process" tabindex="-1">Code Review Process <a class="header-anchor" href="#code-review-process" aria-label="Permalink to &quot;Code Review Process&quot;">​</a></h2><p>All pull requests require at least <strong>two approvals</strong> before merging:</p><ol><li><strong>Automated checks</strong> — CI runs linting, tests, and build verification. All checks must pass.</li><li><strong>Peer review</strong> — A team member reviews the code for correctness, style, and maintainability.</li><li><strong>Design review</strong> — If the change affects visual appearance or interaction patterns, a designer must approve.</li><li><strong>Final approval</strong> — A Cobalt core maintainer gives the final sign-off.</li></ol><p>Reviewers will look for:</p><ul><li>Adherence to coding standards and component patterns</li><li>Adequate test coverage (unit and accessibility)</li><li>Clear, well-structured code with appropriate comments</li><li>Backward compatibility or a proper migration path</li><li>Performance considerations</li></ul><blockquote><p><strong>Note:</strong> Reviews typically happen within 2 business days. If your PR is urgent, tag <code>@cobalt/core-team</code> in the PR description.</p></blockquote><h2 id="communication-channels" tabindex="-1">Communication Channels <a class="header-anchor" href="#communication-channels" aria-label="Permalink to &quot;Communication Channels&quot;">​</a></h2><p>For a full list of support channels, see the <a href="/cobalt-design-system/resources/contact.html">Contact</a> page.</p><h2 id="first-time-contributors" tabindex="-1">First-Time Contributors <a class="header-anchor" href="#first-time-contributors" aria-label="Permalink to &quot;First-Time Contributors&quot;">​</a></h2><p>If this is your first contribution, welcome! Here&#39;s how to get started:</p><ol><li>Look for issues labeled <strong><code>good first issue</code></strong> — these are scoped, well-documented tasks</li><li>Comment on the issue to let others know you&#39;re working on it</li><li>Follow the <a href="./development-setup.html">Development Setup</a> guide to configure your environment</li><li>Don&#39;t hesitate to ask questions in <code>#cobalt-contributors</code></li></ol><p>We&#39;re here to help you succeed with your first pull request.</p>',39)])])}const g=t(n,[["render",s]]);export{p as __pageData,g as default};
